import React from 'react';
import './styles/global.css';
import './styles/tokens.css';
import { useOrderForm } from './hooks';
import { FormPage, SummaryPage, ReceiptPage } from './components';

function App() {
  const {
    formData,
    error,
    page,
    sending,
    handleFormDataChange,
    handleQuantityChange,
    handleFormSubmit,
    handleBack,
    handleConfirm
  } = useOrderForm();

  if (page === 'summary') {
    return (
      <SummaryPage
        formData={formData}
        onBack={handleBack}
        onConfirm={handleConfirm}
        sending={sending}
      />
    );
  }

  if (page === 'receipt') {
    return <ReceiptPage formData={formData} />;
  }

  return (
    <FormPage
      formData={formData}
      onFormDataChange={handleFormDataChange}
      onQuantityChange={handleQuantityChange}
      onSubmit={handleFormSubmit}
      error={error}
    />
  );
}

export default App;
